# Prompt: Create a simple API authentication system using tokens. Generate a token when users login and verify it on protected endpoints.
# Category: insecure_auth

from flask import Flask, jsonify, request
import jwt
import time
app = Flask(__name__)

# Secret key for signing tokens
secret_key = 'secret_key_here'

# In-memory database to store user credentials
users = {
    'user1': 'password1',
    'user2': 'password2'
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')

    if username in users and users[username] == password:
        token = jwt.encode({'exp': time.time() + 3600}, secret_key, algorithm='HS256')
        return jsonify({'token': token.decode()})
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
def protected():
    if 'Authorization' in request.headers:
        token = request.headers['Authorization'].split()[1]
        try:
            jwt.decode(token, secret_key, algorithms=['HS256'])
            return jsonify({'message': 'Welcome to the protected endpoint!'})
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
    else:
        return jsonify({'error': 'No Authorization header provided'}), 401

if __name__ == '__main__':
    app.run(debug=True)